const fs = require('fs');
const path = require('path');

function csvField(val) {
  if (val == null) return '';
  const s = String(val);
  if (s.includes(',') || s.includes('"') || s.includes('\n')) {
    return '"' + s.replace(/"/g, '""') + '"';
  }
  return s;
}

// Regenerate chunks.csv for the 3 failing packages
// These were generated by gen-more-exams.js createPkg function
// The issue was unquoted JSON in examples_json field

const base = 'c:/Users/z1309/Desktop/work/speakGuild/apps/backend/prisma/data/packages';
const fixPkgs = ['exam-cet-4', 'exam-cet-6', 'exam-toefl'];

for (const pkg of fixPkgs) {
  const fp = path.join(base, pkg, 'chunks.csv');
  if (!fs.existsSync(fp)) continue;
  
  // Read the scenes.csv to get scene titles and topics
  const scenesPath = path.join(base, pkg, 'scenes.csv');
  const topicsPath = path.join(base, pkg, 'training_topics.csv');
  
  const scenes = fs.readFileSync(scenesPath, 'utf-8').trim().split('\n').slice(1).filter(l => l.trim());
  const topics = fs.readFileSync(topicsPath, 'utf-8').trim().split('\n').slice(1).filter(l => l.trim());
  
  // Parse scene and topic data
  function parseCSV(line) {
    const parts = []; let cur = '', q = false;
    for (const ch of line) {
      if (ch === '"') { q = !q; continue; }
      if (ch === ',' && !q) { parts.push(cur.trim()); cur = ''; }
      else cur += ch;
    }
    parts.push(cur.trim());
    return parts;
  }
  
  const sceneData = scenes.map(parseCSV);
  const topicData = topics.map(parseCSV);
  
  // Build chunks.csv content
  const header = ['scene_title', 'topic_title', 'category', 'text', 'meaning', 'difficulty', 'description', 'examples_json'];
  const rows = [header.join(',')];
  const exampleJson = JSON.stringify([{ en: 'Let me talk about this.', zh: '让我谈谈这个。' }]);
  
  for (const s of sceneData) {
    const sceneTitle = s[1] || s[0]; // title might be in different positions
    // Find topics for this scene
    const sceneTopics = topicData.filter(t => {
      const ts = (t[0] || '').replace(/^"|"$/g, '');
      const st = (sceneTitle || '').replace(/^"|"$/g, '');
      return ts === st;
    });
    
    for (const t of sceneTopics) {
      const topic = (t[1] || '').replace(/^"|"$/g, '');
      const lvl = (t[5] || 'L2').replace(/^"|"$/g, '');
      const text = `Let me talk about ${topic}.`;
      const meaning = `让我谈谈${topic}。`;
      
      const fields = [
        sceneTitle.replace(/^"|"$/g, ''),
        topic,
        topic,
        text,
        meaning,
        lvl,
        '标准表达。',
        exampleJson,
      ];
      rows.push(fields.map(csvField).join(','));
    }
  }
  
  fs.writeFileSync(fp, rows.join('\n') + '\n');
  console.log('✅ Regenerated ' + pkg + '/chunks.csv (' + (rows.length - 1) + ' rows)');
}

console.log('Done');
